diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 3f3f6c6e0d1a..b69c8ffc099e 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4545,6 +4545,7 @@ static Value *simplifySelectWithFCmp(Value *Cond, Value *T, Value *F,

 /// Given operands for a SelectInst, see if we can fold the result.
 /// If not, this returns null.
+
 static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
                                  const SimplifyQuery &Q, unsigned MaxRecurse) {
   if (auto *CondC = dyn_cast<Constant>(Cond)) {
@@ -4678,6 +4679,20 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
       return ConstantVector::get(NewC);
   }

+  // Recognize absorption patterns for nested selects:
+  // select (select i1 X, i1 Y, i1 false), i1 true, i1 Y  --> Y
+  // select (select i1 X, i1 true, i1 Y), i1 false, i1 Y  --> Y
+  // These correspond to Boolean absorption: (X && Y) || Y = Y and (X || Y) && Y = Y
+  Value *X, *Y;
+  if (match(TrueVal, m_One()) && match(Cond, m_Select(m_Value(X), m_Value(Y), m_ZeroInt())))
+    return Y;
+  if (match(TrueVal, m_ZeroInt()) && match(Cond, m_Select(m_Value(X), m_One(), m_Value(Y))))
+    return Y;
+  if (match(FalseVal, m_One()) && match(Cond, m_Select(m_Value(X), m_ZeroInt(), m_Value(Y))))
+    return Y;
+  if (match(FalseVal, m_ZeroInt()) && match(Cond, m_Select(m_Value(X), m_Value(Y), m_One())))
+    return Y;
+
   if (Value *V =
           simplifySelectWithICmpCond(Cond, TrueVal, FalseVal, Q, MaxRecurse))
     return V;
@@ -4695,6 +4710,7 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
   return nullptr;
 }

+
 Value *llvm::simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
                                 const SimplifyQuery &Q) {
   return ::simplifySelectInst(Cond, TrueVal, FalseVal, Q, RecursionLimit);

